class Solution {
    public long minSumSquareDiff(int[] nums1, int[] nums2, int k1, int k2) {
        long sum = 0;
        int n = nums1.length;
        int[] diff = new int[n];
        for (int i = 0; i < n; i++) {
            diff[i] = Math.abs(nums1[i] - nums2[i]);
            sum += (long) diff[i] * diff[i];
        }
        Arrays.sort(diff);
        int i = n - 1;
        while (k1 > 0 && i >= 0) {
            if (diff[i] > 1) {
                int reduce = Math.min(k1, diff[i] - 1);
                sum -= (long) (2 * reduce - 1) * reduce;
                k1 -= reduce;
                diff[i] -= reduce;
            } else {
                i--;
            }
        }
        i = n - 1;
        while (k2 > 0 && i >= 0) {
            if (diff[i] > 1) {
                int reduce = Math.min(k2, diff[i] - 1);
                sum -= (long) (2 * reduce - 1) * reduce;
                k2 -= reduce;
                diff[i] -= reduce;
            } else {
                i--;
            }
        }
        return sum;
    }
}
